'use client';

import useSWR, { mutate } from 'swr';
import { apiPut, apiPost, fetcher } from '@/lib/api-client';
import { useEffect } from 'react';
import { useWebSocket } from './use-websocket';
import { MasterSettings, EffectiveResolution } from '@/types/settings';

export function useSettings() {
  const { data: settings, error: settingsError, mutate: mutateSettings } = useSWR<MasterSettings>(
    '/api/settings',
    fetcher
  );

  const updateNamespace = async (namespace: string, value: unknown) => {
    await apiPut(`/api/settings/${namespace}`, value);
    mutateSettings();
  };

  const resetNamespace = async (namespace: string) => {
    await apiPost(`/api/settings/reset/${namespace}`);
    mutateSettings();
  };

  const testProvider = async (provider: string) => {
    const result = await apiPost<{ latency_ms: number }>(`/api/settings/test/provider/${provider}`);
    mutateSettings();
    return result;
  };

  const updateVault = async (scope: string, key: string, secret: string) => {
    await apiPost(`/api/settings/vault/${scope}/${key}`, { secret });
    mutateSettings();
  };

  // Handle settings_updated event via WebSocket
  const wsUrl = typeof window !== 'undefined' 
    ? (window.location.protocol === 'https:' ? 'wss://' : 'ws://') + window.location.host + '/api/ws'
    : null;

  const { lastMessage } = useWebSocket(wsUrl);

  useEffect(() => {
    if (lastMessage && (lastMessage.type === 'settings_updated' || lastMessage.event === 'settings_updated')) {
      mutateSettings();
      mutate((key) => typeof key === 'string' && key.includes('/api/settings/effective'));
    }
  }, [lastMessage, mutateSettings]);

  return {
    settings,
    isLoading: !settings && !settingsError,
    isError: settingsError,
    updateNamespace,
    resetNamespace,
    testProvider,
    updateVault,
  };
}

